cases = var_call_t7rZuIs9isALY344MuH26Ivy
if isinstance(cases, str):
    with open(cases, 'r', encoding='utf-8') as f:
        cases = json.load(f)

df_c = pd.DataFrame(cases)
df_c['order_item_id_norm'] = df_c['order_item_id'].astype(str).str.replace('#','', regex=False).str.strip()

