start = pd.Timestamp('2022-08-16')
end = pd.Timestamp('2023-01-16 23:59:59')
df_c['created_ts'] = pd.to_datetime(df_c['createddate'], errors='coerce', utc=True).dt.tz_convert(None)
df_c = df_c[(df_c['created_ts']>=start) & (df_c['created_ts']<=end)]

